previewCss:
.darma-loader-darma-custom-519 {color: var(--loader-color, #0f766e);
  --loader-secondary-color: var(--loader-secondary-color, #5eead4);
  --loader-bg: var(--loader-bg, #ffffff);
   height: 66px;
   aspect-ratio: 1;
   display: grid;
}
.darma-loader-darma-custom-519:before, .darma-loader-darma-custom-519:after  {
  content: "";
   --c:no-repeat linear-gradient(currentColor 0 0);
   background: var(--c), var(--c);
   background-size: 25% 50%;
   animation: darma-loader-darma-custom-519-l5 1.5s infinite linear;
}
.darma-loader-darma-custom-519:after  {
  transform: scale(-1);
}
@keyframes darma-loader-darma-custom-519-l5  {
  0%, 5% {background-position:33.4% 100%,66.6% 100%}
25% {background-position:33.4% 100%,100% 0}
50% {background-position:0 0,100% 0}
75% {background-position:0 0,66.6% 100%}
95%, 100% {background-position:33.4% 100%,66.6% 100%}
}

